parameters.jsCode:
const crypto = require('crypto'); 

const inputItem = $input.first();

if (!inputItem?.binary){throw new Error ("No se encontraron datos binarios en la entrada del nodo.");
                       }
const [binaryKey] = Object.keys(inputItem.binary);

if (!binaryKey) {throw new Error ("El objeto binario está vacío o mal estructurado.");
                }

let parsedData;

try {
  const binaryBuffer = await this.helpers.getBinaryDataBuffer(0,binaryKey);
  const rawString = binaryBuffer.toString('utf-8');
  parsedData = JSON.parse(rawString)
} catch (error) { throw new Error (`Fallo al parsear el archivo binario a JSON: ${error.message}`);
        }

const itemsToProcess = Array.isArray(parsedData) ? parsedData : [parsedData];

return itemsToProcess.flatMap(item =>
  (item.clinical_object || []).map((co, i) => ({
    json: {
      id_code_combination: item.id_code_combination,
      icf_codes: item.icf_codes,
      icf_names: item.icf_names,
      id_clinical_text: co.id_clinical_text,
      uuid_clinical_text: crypto.randomUUID(),
      clinical_text: co.clinical_text,
    }
  }))
);

const textExtractor = (json) => {
    return json.response ||
           json.choices?.[0]?.message?.content ||
           json.output ||
           json.message;
};

const cleanMarkdownJSON = (text) => {
    const match = text.match(/```(?:json)?\s*([\s\S]*?)\s*```/);
    return match ? match[1] : text;
};

const llmDataParser = (rawText, index) => {
    const cleanText = cleanMarkdownJSON(rawText);
    try {
        return JSON.parse(cleanText.trim());
    } catch (error) {
        throw new Error(`Invalid JSON in iteration ${index}. Text: ${cleanText}`);
    }
};

const formatPredictedCodes = (parsedData) => {
    const predictedCodes = parsedData.clinical_object || parsedData.historias_clinicas || parsedData.predicted_icf_codes || parsedData;
    if (!Array.isArray(predictedCodes)) return predictedCodes;

    return predictedCodes.map(story => story.predicted_icf_codes || story);
};

const originalData = $('binary_json_parser').all();
const llm_output = $input.all();

const structuredCodifiedJson = llm_output.map((item, index) => {
    const rawText = textExtractor(item.json);

    if (!rawText) {
        throw new Error(`There's no text variable in item ${index}.`);
    }

    const parsedLlmData = llmDataParser(rawText, index);
    const extracted_codes = formatPredictedCodes(parsedLlmData);
    const originalDataConnection = originalData[$runIndex].json;

    return {
        json: {
            id_code_combination: originalDataConnection.id_code_combination,
            icf_codes: originalDataConnection.icf_codes,
            icf_names: originalDataConnection.icf_names,
            predicted_icf_codes: extracted_codes,
            id_clinical_text: originalDataConnection.id_clinical_text,
            clinical_text: originalDataConnection.clinical_text
        }
    };
});

return structuredCodifiedJson;

// Only the clinical_text for the LLM  
for (const item of $input.all()){
    item.json = {
    clinical_text: item.json.clinical_text,
    }};
return $input.all()

// 1. Recogemos los 10 ítems individuales que salen del bucle
const todosLosPacientes = $input.all().map(item => item.json);

// 2. Lo convertimos a una cadena de texto JSON pura y formateada (array real)
const jsonPlano = JSON.stringify(todosLosPacientes, null, 2);

// 3. Lo metemos en una única propiedad limpia para que el siguiente nodo lo lea
return {
  json: {
    archivo_final: jsonPlano
  }
};
